// Player boot AMD module — hand-wrapped as AMD since the dev environment lacks
// `grunt amd`. ES5-compatible mirror of amd/src/player_boot.js. See that file
// for rationale and comments.
//
// The native import() MUST survive as import() so the browser loads the player
// as a real ES module outside RequireJS; the Function-constructor indirection
// keeps the build step (and RequireJS) from rewriting it. Mirrors the
// esmImport helper in mod_fastpix/amd/build/player.min.js.
define([], function() {
    "use strict";

    var esmImport = function(url) {
        return Function('u', 'return import(u);')(url);
    };

    function mount(wrapperEl, config) {
        if (!wrapperEl || !config) {
            return;
        }
        if (wrapperEl.querySelector('fastpix-player')) {
            return;
        }

        var loadDeps = Promise.resolve();
        if (!window.Hls) {
            loadDeps = esmImport(config.hlsliburl).then(function(hlsMod) {
                window.Hls = hlsMod.default || hlsMod.Hls || hlsMod;
            });
        }
        loadDeps.then(function() {
            if (!window.customElements.get('fastpix-player')) {
                return esmImport(config.playerliburl);
            }
            return null;
        }).then(function() {
            if (wrapperEl.querySelector('fastpix-player')) {
                return;
            }
            var data = wrapperEl.dataset;
            var el = document.createElement('fastpix-player');
            el.setAttribute('playback-id', data.playbackId || '');
            if (data.playbackToken) {
                el.setAttribute('token', data.playbackToken);
            }
            if (data.drmToken) {
                el.setAttribute('drm-token', data.drmToken);
            }
            el.setAttribute('stream-type', 'on-demand');
            if (data.accentColor) {
                el.setAttribute('accent-color', data.accentColor);
            }
            if (data.videoTitle) {
                el.setAttribute('metadata-video-title', data.videoTitle);
            }
            el.style.cssText = 'display:block;width:100%;aspect-ratio:16/9;';
            wrapperEl.appendChild(el);
        }).catch(function(err) {
            if (window.console) {
                window.console.error('[filter_fastpix] player load failed', err);
            }
        });
    }

    function init(config) {
        var wrappers = document.querySelectorAll('[data-region="fastpix-player-wrapper"]');
        Array.prototype.forEach.call(wrappers, function(wrapperEl) {
            mount(wrapperEl, config);
        });
    }

    return {
        init: init
    };
});
